        let headerRows = [];
        for (let r = range.s.r; r <= range.e.r; r++) {
            const cell = ws[XLSX.utils.encode_cell({ r, c: 0 })];
            if (cell && cell.v) {
                const val = String(cell.v);
                if (val.includes('PROVINCE') || val.includes('OFFICE') || val.includes('REMARKS') ||
