                                            key={p}
                                            className={`scope-item-modern ${selected ? 'selected' : ''}`}
                                            onClick={() => {
                                                setNewEvent(prev => {
                                                    const provinces = selected ? prev.provinces.filter(x => x !== p) : [...prev.provinces, p];
                                                    return {
                                                        ...prev,
                                                        provinces,
                                                        sendToAllUsers: provinces.length === allProvinces.length
                                                    };
                                                });
                                            }}
                                        >
                                            {p}
                                        </button>
                                    );
                                })}
